<script setup lang="ts">import{computed,onMounted,ref}from"vue";import{useRouter}from"vue-router";import{ChevronRight,FileText,MessageSquareWarning,Info,MessagesSquare,LogOut,UsersRound}from"lucide-vue-next";import{api,session,type Order,type Person}from"../api";import{openLogin}from"../auth-state";const router=useRouter(),orders=ref<Order[]>([]),people=ref<Person[]>([]),logged=computed(()=>!!session.get()),phone=ref(localStorage.getItem("patient_phone")||"");async function load(){if(!logged.value)return;[orders.value,people.value]=await Promise.all([api.orders(),api.people()])}onMounted(load);async function logout(){session.clear();localStorage.removeItem("patient_phone");await router.replace("/");router.go(0)}</script><template><main class="profile"><section class="profile-head" @click="!logged&&openLogin('/profile')"><div class="user-avatar">{{logged?phone.slice(-1):'人'}}</div><div><h1>{{logged?phone:'点击登录'}}</h1><p>{{logged?'已登录 · 信息安全保护':'登录后管理预约和就诊人'}}</p></div><ChevronRight/></section><section class="profile-orders"><h2>我的预约</h2><div><router-link to="/orders?tab=reserved"><FileText/><span>已预约</span></router-link><router-link to="/orders?tab=completed"><FileText/><span>已完成</span></router-link><router-link to="/orders?tab=cancelled"><FileText/><span>已取消</span></router-link></div></section><section v-if="logged" class="people-card"><header><h2>就诊人管理</h2><span>{{people.length}} / 10</span></header><div v-for="p in people" :key="p.id"><UsersRound/><b>{{p.name}}</b><small>{{p.phone}} · {{p.idCardMasked}}</small></div></section><section class="profile-menu"><a><FileText/><span>用户协议</span><ChevronRight/></a><router-link to="/feedback"><MessageSquareWarning/><span>投诉建议</span><ChevronRight/></router-link><a><Info/><span>关于我们</span><ChevronRight/></a><router-link to="/faq"><MessagesSquare/><span>常见问题</span><ChevronRight/></router-link><button v-if="logged" @click="logout"><LogOut/><span>退出登录</span><ChevronRight/></button></section></main></template>
